import React, { useEffect, useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const AdminDashboard = () => {
  const [user, setUser] = useState(null);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState('');
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');
  const [viewMode, setViewMode] = useState('overview');
  const [balanceInputs, setBalanceInputs] = useState({});
  const [userFilter, setUserFilter] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedUserId, setSelectedUserId] = useState('');
  const [customTitle, setCustomTitle] = useState('');
  const [customMessage, setCustomMessage] = useState('');
  const [customType, setCustomType] = useState('info');
  const [notificationLoading, setNotificationLoading] = useState(false);
  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  const headers = {
    Authorization: `Bearer ${token}`
  };

  const loadProfile = useCallback(async () => {
    if (!token) {
      navigate('/login');
      return;
    }

    try {
      const res = await axios.get('http://localhost:5000/api/auth/profile', { headers });
      if (!res.data.isAdmin) {
        navigate('/dashboard');
        return;
      }
      setUser(res.data);
    } catch (err) {
      localStorage.removeItem('token');
      localStorage.removeItem('isAdmin');
      navigate('/login');
    }
  }, [headers, navigate, token]);

  const loadUsers = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/admin/users', { headers });
      setUsers(res.data);
    } catch (err) {
      setError(err?.response?.data?.error || 'Could not load users');
    }
  };

  useEffect(() => {
    loadProfile();
  }, [loadProfile]);

  useEffect(() => {
    if (user?.isAdmin) {
      loadUsers();
      setLoading(false);
    }
  }, [user]);

  const handleUserAction = async (userId, action, body = {}) => {
    setActionLoading(userId);
    setError('');
    setMessage('');

    try {
      let res;
      if (action === 'approve' || action === 'reject') {
        res = await axios.put(`http://localhost:5000/api/admin/kyc/${userId}/${action}`, {}, { headers });
      } else if (action === 'reset') {
        res = await axios.put(`http://localhost:5000/api/admin/users/${userId}/reset-password`, body, { headers });
      } else if (action === 'ban' || action === 'unban') {
        res = await axios.put(`http://localhost:5000/api/admin/users/${userId}/${action}`, {}, { headers });
      } else if (action === 'delete') {
        res = await axios.delete(`http://localhost:5000/api/admin/users/${userId}`, { headers });
      } else if (action === 'balance') {
        res = await axios.put(`http://localhost:5000/api/admin/users/${userId}/balance`, body, { headers });
      }
      setMessage(res.data.message);
      await loadUsers();
    } catch (err) {
      setError(err?.response?.data?.error || 'Action failed');
    } finally {
      setActionLoading('');
    }
  };

  const getFileUrl = (filePath) => {
    if (!filePath) return null;
    const normalized = filePath.replace(/\\/g, '/');
    return `http://localhost:5000/${normalized}`;
  };

  const handleBalanceChange = (userId, value) => {
    setBalanceInputs(prev => ({ ...prev, [userId]: value }));
  };

  const handleSendNotification = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');
    setNotificationLoading(true);

    if (!selectedUserId) {
      setError('Please choose a user to notify.');
      setNotificationLoading(false);
      return;
    }
    if (!customTitle.trim() || !customMessage.trim()) {
      setError('Both title and message are required.');
      setNotificationLoading(false);
      return;
    }

    try {
      const res = await axios.post(`http://localhost:5000/api/admin/users/${selectedUserId}/notify`, {
        title: customTitle,
        message: customMessage,
        type: customType
      }, { headers });
      setMessage(res.data.message);
      setCustomTitle('');
      setCustomMessage('');
      setCustomType('info');
    } catch (err) {
      setError(err?.response?.data?.error || 'Could not send notification');
    } finally {
      setNotificationLoading(false);
    }
  };

  const selectMessageTarget = (userId) => {
    setSelectedUserId(userId);
  };

  const pendingUsers = users.filter(userItem => userItem.kycDetails?.kycStatus === 'pending');

  if (loading) {
    return <div className="page-content"><div className="card">Loading admin dashboard...</div></div>;
  }

  return (
    <div className="dashboard-layout">
      <aside className="dashboard-sidebar">
        <div className="sidebar-user">
          <div className="user-avatar">A</div>
          <div className="user-info">
            <h4>{user?.username || 'Admin'}</h4>
            <p>{user?.email || 'admin@charity.com'}</p>
          </div>
        </div>

        <nav className="sidebar-nav">
          <button className={`nav-item ${viewMode === 'pending' ? 'active' : ''}`} onClick={() => setViewMode('pending')}>
            <span className="icon overview"></span> Pending KYC
          </button>
          <button className={`nav-item ${viewMode === 'users' ? 'active' : ''}`} onClick={() => setViewMode('users')}>
            <span className="icon transactions"></span> All Users
          </button>
        </nav>

        <div className="sidebar-footer">
          <button className="btn-logout" onClick={() => {
            localStorage.removeItem('token');
            localStorage.removeItem('isAdmin');
            navigate('/login');
          }}>Logout</button>
        </div>
      </aside>

      <main className="dashboard-main">
        <div className="content-section">
          <h2>Admin Panel</h2>
          <p>Review all users, manage accounts, and approve or reject KYC submissions.</p>

          <div className="dashboard-summary-grid">
            <div className="summary-card summary-card-primary">
              <div className="summary-label">Pending KYC</div>
              <div className="summary-value">{pendingUsers.length}</div>
              <div className="summary-note">Action required on users waiting for approval.</div>
            </div>
            <div className="summary-card">
              <div className="summary-label">Total users</div>
              <div className="summary-value">{users.length}</div>
              <div className="summary-note">Registered accounts in the system.</div>
            </div>
            <div className="summary-card">
              <div className="summary-label">Admin</div>
              <div className="summary-value">{user?.username}</div>
              <div className="summary-note">Signed in as administrator.</div>
            </div>
          </div>

          <div className="admin-message-panel">
            <div className="message-panel-header">
              <div>
                <h3>Send custom user notification</h3>
                <p>Deliver important updates and announcements directly to a user.</p>
              </div>
            </div>

            <form className="message-form" onSubmit={handleSendNotification}>
              <div className="form-row">
                <label htmlFor="message-user">Select user</label>
                <select id="message-user" value={selectedUserId} onChange={(e) => setSelectedUserId(e.target.value)}>
                  <option value="">Choose a user</option>
                  {users.filter((u) => !u.isAdmin).map((userItem) => (
                    <option key={userItem._id} value={userItem._id}>{userItem.username} ({userItem.email})</option>
                  ))}
                </select>
              </div>

              <div className="form-row">
                <label htmlFor="message-title">Title</label>
                <input
                  id="message-title"
                  type="text"
                  placeholder="Notification title"
                  value={customTitle}
                  onChange={(e) => setCustomTitle(e.target.value)}
                />
              </div>

              <div className="form-row">
                <label htmlFor="message-body">Message</label>
                <textarea
                  id="message-body"
                  placeholder="Write your message here"
                  value={customMessage}
                  onChange={(e) => setCustomMessage(e.target.value)}
                />
              </div>

              <div className="form-row split-row">
                <div>
                  <label htmlFor="message-type">Type</label>
                  <select id="message-type" value={customType} onChange={(e) => setCustomType(e.target.value)}>
                    <option value="info">Info</option>
                    <option value="success">Success</option>
                    <option value="warning">Warning</option>
                    <option value="danger">Alert</option>
                  </select>
                </div>
                <button type="submit" className="btn-send" disabled={notificationLoading}>
                  {notificationLoading ? 'Sending...' : 'Send Notification'}
                </button>
              </div>
            </form>
          </div>

          {error && <div className="status-message error">{error}</div>}
          {message && <div className="status-message success">{message}</div>}

          <div className="card">
            <h3>{viewMode === 'pending' ? 'Pending KYC Applications' : 'All Registered Users'}</h3>
            {viewMode === 'pending' ? (
              pendingUsers.length === 0 ? (
                <p>No pending applications at the moment.</p>
              ) : (
                <div className="kyc-table">
                  {pendingUsers.map((app) => (
                    <div key={app._id} className="kyc-card">
                      <div className="kyc-card-header">
                        <div>
                          <h4>{app.username}</h4>
                          <p>{app.email}</p>
                        </div>
                        <span className="status pending">Pending</span>
                      </div>

                      <div className="kyc-card-body">
                        <p><strong>Full name:</strong> {app.kycDetails.fullName || '–'}</p>
                        <p><strong>Country:</strong> {app.kycDetails.country || '–'}</p>
                        <p><strong>Phone:</strong> {app.kycDetails.countryCode || ''} {app.kycDetails.phoneNumber || '–'}</p>
                        <p><strong>Additional details:</strong> {app.kycDetails.additionalDetails || '–'}</p>
                        <div className="kyc-documents">
                          <div>
                            <span>ID Front:</span> {app.kycDetails.idCardFront ? <a href={getFileUrl(app.kycDetails.idCardFront)} target="_blank" rel="noreferrer">View</a> : 'Not uploaded'}
                          </div>
                          <div>
                            <span>ID Back:</span> {app.kycDetails.idCardBack ? <a href={getFileUrl(app.kycDetails.idCardBack)} target="_blank" rel="noreferrer">View</a> : 'Not uploaded'}
                          </div>
                        </div>
                      </div>

                      <div className="kyc-card-actions">
                        <button className="btn-approve" disabled={actionLoading === app._id} onClick={() => handleUserAction(app._id, 'approve')}>
                          {actionLoading === app._id ? 'Processing...' : 'Approve'}
                        </button>
                        <button className="btn-reject" disabled={actionLoading === app._id} onClick={() => handleUserAction(app._id, 'reject')}>
                          {actionLoading === app._id ? 'Processing...' : 'Reject'}
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )
            ) : (
              users.length === 0 ? (
                <p>No users registered yet.</p>
              ) : (
                <div className="kyc-table">
                  {users.map((app) => (
                    <div key={app._id} className="kyc-card">
                      <div className="kyc-card-header">
                        <div>
                          <h4>{app.username}</h4>
                          <p>{app.email}</p>
                        </div>
                        <span className={`status ${app.isBanned ? 'danger' : 'verified'}`}>
                          {app.isBanned ? 'Banned' : 'Active'}
                        </span>
                      </div>

                      <div className="kyc-card-body">
                        <p><strong>Balance:</strong> ${app.balance.toFixed(2)}</p>
                        <div className="balance-update-row">
                          <input
                            type="number"
                            min="0"
                            step="0.01"
                            value={balanceInputs[app._id] ?? app.balance.toFixed(2)}
                            onChange={(e) => handleBalanceChange(app._id, e.target.value)}
                          />
                          <button
                            className="btn-update"
                            disabled={actionLoading === app._id}
                            onClick={() => handleUserAction(app._id, 'balance', { balance: Number(balanceInputs[app._id] ?? app.balance) })}
                          >
                            {actionLoading === app._id ? 'Processing...' : 'Update Balance'}
                          </button>
                        </div>
                        <p><strong>KYC status:</strong> {app.kycDetails?.kycStatus || 'Not submitted'}</p>
                        <p><strong>Full name:</strong> {app.kycDetails?.fullName || 'N/A'}</p>
                        <p><strong>Country:</strong> {app.kycDetails?.country || 'N/A'}</p>
                        <p><strong>Phone:</strong> {app.kycDetails?.countryCode || ''} {app.kycDetails?.phoneNumber || 'N/A'}</p>
                        <p><strong>Additional details:</strong> {app.kycDetails?.additionalDetails || 'N/A'}</p>
                        <p><strong>Submitted:</strong> {app.kycDetails?.submittedAt ? new Date(app.kycDetails.submittedAt).toLocaleString() : 'N/A'}</p>
                        <p><strong>Banned:</strong> {app.isBanned ? 'Yes' : 'No'}</p>
                        <div className="kyc-documents">
                          <div>
                            <span>ID Front:</span> {app.kycDetails?.idCardFront ? <a href={getFileUrl(app.kycDetails.idCardFront)} target="_blank" rel="noreferrer">View</a> : 'No file'}
                          </div>
                          <div>
                            <span>ID Back:</span> {app.kycDetails?.idCardBack ? <a href={getFileUrl(app.kycDetails.idCardBack)} target="_blank" rel="noreferrer">View</a> : 'No file'}
                          </div>
                        </div>
                      </div>

                      <div className="kyc-card-actions">
                        {app.kycDetails?.kycStatus === 'pending' && (
                          <>
                            <button className="btn-approve" disabled={actionLoading === app._id} onClick={() => handleUserAction(app._id, 'approve')}>
                              {actionLoading === app._id ? 'Processing...' : 'Approve'}
                            </button>
                            <button className="btn-reject" disabled={actionLoading === app._id} onClick={() => handleUserAction(app._id, 'reject')}>
                              {actionLoading === app._id ? 'Processing...' : 'Reject'}
                            </button>
                          </>
                        )}
                        <button className="btn-approve" disabled={actionLoading === app._id} onClick={() => handleUserAction(app._id, 'reset', { password: 'Password123!' })}>
                          {actionLoading === app._id ? 'Processing...' : 'Reset Password'}
                        </button>
                        <button className="btn-secondary" onClick={() => selectMessageTarget(app._id)}>
                          Message
                        </button>
                        <button className={`btn-${app.isBanned ? 'approve' : 'reject'}`} disabled={actionLoading === app._id} onClick={() => handleUserAction(app._id, app.isBanned ? 'unban' : 'ban')}>
                          {actionLoading === app._id ? 'Processing...' : app.isBanned ? 'Unban' : 'Ban'}
                        </button>
                        {!app.isAdmin && (
                          <button className="btn-reject" disabled={actionLoading === app._id} onClick={() => handleUserAction(app._id, 'delete')}>
                            {actionLoading === app._id ? 'Processing...' : 'Delete'}
                          </button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default AdminDashboard;
